const input = $input.first().json;
const body = input.body && typeof input.body === 'object' ? input.body : input;

function asString(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

const messageId = asString(body.message_id);

return [
  {
    json: {
      message_id: messageId,
      include_body: body.include_body !== false && body.include_body !== 'false',
      include_thread: body.include_thread !== false && body.include_thread !== 'false',
      source: asString(body.source) || 'n8n-email-read'
    }
  }
];

const message = $input.first().json;

function decodeBase64Url(data) {
  if (!data) return '';
  let normalized = String(data).replace(/-/g, '+').replace(/_/g, '/');
  while (normalized.length % 4) normalized += '=';
  return Buffer.from(normalized, 'base64').toString('utf8');
}

function getHeader(payload, name) {
  const headers = payload?.headers || [];
  const found = headers.find((header) => String(header.name).toLowerCase() === String(name).toLowerCase());
  return found ? found.value : '';
}

function collectBodyParts(part, out = { text: [], html: [] }) {
  if (!part) return out;

  const mimeType = part.mimeType || '';
  const data = part.body?.data;

  if (data && mimeType === 'text/plain') {
    out.text.push(decodeBase64Url(data));
  } else if (data && mimeType === 'text/html') {
    out.html.push(decodeBase64Url(data));
  }

  for (const child of part.parts || []) {
    collectBodyParts(child, out);
  }

  return out;
}

const bodyParts = collectBodyParts(message.payload || {});
const bodyText = bodyParts.text.join('\n\n').trim();
const bodyHtml = bodyParts.html.join('\n\n').trim();

const payload = message.payload || {};
const subject = getHeader(payload, 'Subject');
const from = getHeader(payload, 'From');
const to = getHeader(payload, 'To');
const cc = getHeader(payload, 'Cc');
const date = getHeader(payload, 'Date');
const messageIdHeader = getHeader(payload, 'Message-ID');

return [
  {
    json: {
      message_id: message.id,
      thread_id: message.threadId,
      subject,
      from,
      to,
      cc,
      date,
      message_id_header: messageIdHeader,
      snippet: message.snippet || '',
      label_ids: message.labelIds || [],
      body: bodyText || bodyHtml || '',
      body_format: bodyText ? 'text/plain' : (bodyHtml ? 'text/html' : 'unknown'),
      send_email: false,
      source: 'n8n-email-read'
    }
  }
];
